# @记
# 需求：创建、查看、恢复快照
# 注意：快照同时备份packs/目录，恢复后建议重启中枢
# @毕

import json, os, shutil
from datetime import datetime

PACKS_DIR = os.path.join(_base_dir, "packs")

def _list_snaps():
    if not os.path.exists(_snap_dir): return []
    return sorted([f for f in os.listdir(_snap_dir) if f.endswith(".json")], reverse=True)

def _snap_full():
    # 内核只备份json，packs/由本功能自己决定
    ts = _snap()
    packs_backed = False
    if os.path.isdir(PACKS_DIR):
        shutil.copytree(PACKS_DIR, os.path.join(_snap_dir, f"packs_{ts}"))
        packs_backed = True
    return ts, packs_backed

print("\n快照管理：")
print("  1. 创建快照  2. 查看快照  3. 恢复快照")
c = input("选择：").strip()

if c == "1":
    ts, has_packs = _snap_full()
    print(f"ok 快照已保存：snapshot_{ts}.json")
    if has_packs:
        print(f"   packs/ 同步备份：packs_{ts}/")

elif c == "2":
    files = _list_snaps()
    if not files:
        print("暂无快照。")
    else:
        for i, f in enumerate(files, 1):
            tag = " + packs/" if os.path.isdir(os.path.join(_snap_dir, f"packs_{f[9:24]}")) else ""
            print(f"  {i}. {f}{tag}")

elif c == "3":
    files = _list_snaps()
    if not files:
        print("暂无快照。")
    else:
        for i, f in enumerate(files, 1):
            tag = " + packs/" if os.path.isdir(os.path.join(_snap_dir, f"packs_{f[9:24]}")) else ""
            print(f"  {i}. {f}{tag}")
        try:
            name = files[int(input("\n恢复哪个？编号：").strip()) - 1]
            if input(f"确认恢复「{name}」？当前数据会被覆盖(y/n)：").strip().lower() == "y":
                with open(os.path.join(_snap_dir, name), encoding="utf-8") as f:
                    restored = json.load(f)
                _atomic_save(restored)
                ts_tag = name[9:24]
                packs_bak = os.path.join(_snap_dir, f"packs_{ts_tag}")
                if os.path.isdir(packs_bak):
                    if os.path.exists(PACKS_DIR):
                        shutil.rmtree(PACKS_DIR)
                    shutil.copytree(packs_bak, PACKS_DIR)
                    print("ok packs/ 已同步恢复")
                print("ok 恢复成功，请重启中枢。")
                exit(0)
        except (ValueError, IndexError):
            print("无效编号。")

input("\n回车继续...")

