                        chosen = list(reversed(history))[int(roll) - 1]
                        if input(f"  确认恢复到{chosen['time']}？(y/n)：").strip().lower() == "y":
                            _snap()
                            hist = info.get("history", [])
                            hist.append({"time": _now(), "code": info["code"], "memo": info.get("memo", {})})
                            data["actions"][name] = {
                                **info, "code": chosen["code"],
                                "memo": chosen.get("memo", {}),
                                "modified": _now(),
                                "history": hist[-10:]
                            }
                            _atomic_save(data)
                            print(f"\n✅ 已恢复到{chosen['time']}的版本。")
                    except (ValueError, IndexError): print("⚠️  无效编号。")
        code = info.get("code", "")
