# @记
# 需求：协议管理，读写zhongqu_protocol.json，子菜单操作
# 注意：协议文件与中枢同目录
# @毕
import json, os
from datetime import datetime

PROTO_FILE = os.path.join(_base_dir, "zhongqu_protocol.json")

def _proto_load():
    with open(PROTO_FILE, encoding="utf-8") as f:
        return json.load(f)

def _proto_save(d):
    tmp = PROTO_FILE + ".tmp." + str(os.getpid())
    try:
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(d, f, ensure_ascii=False, indent=2)
            f.flush()
            os.fsync(f.fileno())
        if os.path.exists(PROTO_FILE):
            os.remove(PROTO_FILE)
        os.rename(tmp, PROTO_FILE)
        return True
    except Exception as e:
        print(f"⚠️ 写入失败：{e}")
        return False

def _has_content(node):
    return bool(node.get("content") or node.get("children"))

def _proto_show(d):
    print("\n📜 协议结构")
    print(f"  版本：{d['meta']['version']}  状态：{d['meta']['status']}")
    print()
    print(f"  第1层：{d['layer_1']['name']} — {d['layer_1']['description']}")
    print(f"  第2层：{d['layer_2']['name']} — {d['layer_2'].get('content','')}")
    print()
    c3 = d['layer_3'].get('content', {})
    print(f"  第3层：{d['layer_3']['name']}")
    print(f"    人：{c3.get('human','')}")
    print(f"    AI：{c3.get('ai','')}")
    print()
    print(f"  第4层：{d['layer_4']['name']}")
    nodes = d['layer_4']['nodes']
    for k, v in nodes.items():
        marker = "◆" if _has_content(v) else "◇"
        print(f"    {marker} {k}. {v['name']}")
        for ck, cv in v.get('children', {}).items():
            cm = "◆" if _has_content(cv) else "◇"
            print(f"         {cm} {ck} {cv['name']}")
            for dk, dv in cv.get('children', {}).items():
                dm = "◆" if _has_content(dv) else "◇"
                print(f"              {dm} {dk} {dv['name']}")
    print("\n  ◆有内容  ◇空节点")

def _print_node_content(node, indent="  "):
    content = node.get('content')
    if content:
        if isinstance(content, str):
            print(f"{indent}{content}")
        elif isinstance(content, dict):
            for k, v in content.items():
                print(f"{indent}• {k}：{v}")
    children = node.get('children', {})
    if children:
        print(f"{indent}子节点：")
        for ck, cv in children.items():
            has = "◆" if _has_content(cv) else "◇"
            print(f"{indent}  {has} {ck} {cv['name']}")
            cc = cv.get('content')
            if cc:
                if isinstance(cc, str):
                    print(f"{indent}      {cc}")
                elif isinstance(cc, dict):
                    for dk, dv in cc.items():
                        print(f"{indent}      • {dk}：{dv}")
            for dk, dv in cv.get('children', {}).items():
                dhas = "◆" if _has_content(dv) else "◇"
                print(f"{indent}       {dhas} {dk} {dv['name']}")
                dc = dv.get('content')
                if dc:
                    if isinstance(dc, str):
                        print(f"{indent}           {dc}")
                    elif isinstance(dc, dict):
                        for ek, ev in dc.items():
                            print(f"{indent}           • {ek}：{ev}")
    if not content and not children:
        print(f"{indent}（暂无内容）")

def _proto_get_node(nodes, idx):
    parts = idx.split(".")
    if len(parts) == 1:
        return nodes.get(idx)
    elif len(parts) == 2:
        return nodes.get(parts[0], {}).get("children", {}).get(idx)
    elif len(parts) == 3:
        parent = nodes.get(parts[0], {}).get("children", {}).get(f"{parts[0]}.{parts[1]}", {})
        return parent.get("children", {}).get(idx)
    return None

def _proto_view(d):
    _proto_show(d)
    idx = input("\n查看节点编号（回车跳过）：").strip()
    if not idx:
        return
    node = _proto_get_node(d['layer_4']['nodes'], idx)
    if not node:
        print("❌ 未找到节点"); return
    print(f"\n{'='*35}")
    print(f"  {idx}. {node['name']}")
    print(f"{'='*35}")
    _print_node_content(node)

def _proto_add(d):
    nodes = d['layer_4']['nodes']
    _proto_show(d)
    parent = input("\n挂在哪个节点下（如1或2.1，回车新建一级）：").strip()
    name = input("节点名称：").strip()
    if not name:
        print("❌ 名称不能为空"); return
    content = input("节点内容（可留空）：").strip()
    new_node = {"name": name}
    if content:
        new_node["content"] = content
    if not parent:
        existing_top = [k for k in nodes if k.isdigit()]
        idx = str(max([int(k) for k in existing_top], default=0) + 1)
        nodes[idx] = new_node
        print(f"✅ 已添加 {idx} {name}")
    elif "." not in parent:
        if parent in nodes:
            children = nodes[parent].setdefault("children", {})
            existing = [k for k in children if k.startswith(f"{parent}.") and k.count(".") == 1]
            idx = f"{parent}.{len(existing)+1}"
            children[idx] = new_node
            print(f"✅ 已添加 {idx} {name}")
        else:
            print("❌ 父节点不存在"); return
    else:
        parts = parent.split(".")
        parent_node = nodes.get(parts[0], {}).get("children", {}).get(parent)
        if not parent_node:
            print("❌ 父节点不存在"); return
        children = parent_node.setdefault("children", {})
        existing = [k for k in children if k.startswith(f"{parent}.")]
        idx = f"{parent}.{len(existing)+1}"
        children[idx] = new_node
        print(f"✅ 已添加 {idx} {name}")
    _proto_save(d)

def _proto_edit(d):
    nodes = d['layer_4']['nodes']
    _proto_show(d)
    idx = input("\n要编辑的节点编号（如1或2.1或2.1.1）：").strip()
    node = _proto_get_node(nodes, idx)
    if not node:
        print("❌ 未找到节点"); return
    print(f"当前名称：{node['name']}")
    new_name = input("新名称（留空不改）：").strip()
    current = node.get('content', '无')
    if isinstance(current, dict):
        current = json.dumps(current, ensure_ascii=False)
    print(f"当前内容：{current}")
    print("（输入新内容 / 留空不改 / 输入-删除内容）")
    new_content = input("新内容：").strip()
    if new_name:
        node["name"] = new_name
    if new_content == "-":
        node.pop("content", None)
    elif new_content:
        node["content"] = new_content
    _proto_save(d)
    print("✅ 已更新")

def _proto_delete(d):
    nodes = d['layer_4']['nodes']
    _proto_show(d)
    idx = input("\n要删除的节点编号（如1或2.1或2.1.1）：").strip()
    confirm = input(f"确认删除 {idx}？(y/n)：").strip()
    if confirm != "y":
        print("已取消"); return
    parts = idx.split(".")
    if len(parts) == 1:
        if idx in nodes:
            del nodes[idx]
            print("✅ 已删除")
        else:
            print("❌ 未找到")
    elif len(parts) == 2:
        children = nodes.get(parts[0], {}).get("children", {})
        if idx in children:
            del children[idx]
            print("✅ 已删除")
        else:
            print("❌ 未找到")
    elif len(parts) == 3:
        parent = nodes.get(parts[0], {}).get("children", {}).get(f"{parts[0]}.{parts[1]}", {})
        children = parent.get("children", {})
        if idx in children:
            del children[idx]
            print("✅ 已删除")
        else:
            print("❌ 未找到")
    _proto_save(d)

def _proto_export_md(d):
    meta = d['meta']
    out = []
    out.append("# zhongqu_protocol\n\n")
    out.append(f"版本：{meta['version']}  状态：{meta['status']}  更新：{datetime.now().strftime('%Y-%m-%d')}\n\n---\n\n")
    out.append(f"## 第一层：{d['layer_1']['name']}\n\n{d['layer_1']['description']}\n\n")
    out.append(f"## 第二层：{d['layer_2']['name']}\n\n{d['layer_2'].get('content','')}\n\n")
    c3 = d['layer_3'].get('content', {})
    out.append(f"## 第三层：{d['layer_3']['name']}\n\n")
    out.append(f"> 人：{c3.get('human','')}\n\n> AI：{c3.get('ai','')}\n\n")
    l4 = d['layer_4']
    out.append(f"## 第四层：{l4['name']}\n\n{l4['description']}\n\n")
    for k, v in l4['nodes'].items():
        out.append(f"### {k}. {v['name']}\n\n")
        content = v.get('content')
        if content:
            if isinstance(content, str):
                out.append(f"{content}\n\n")
            elif isinstance(content, dict):
                for ck, cv in content.items():
                    out.append(f"- **{ck}**：{cv}\n")
                out.append("\n")
        for ck, cv in v.get('children', {}).items():
            out.append(f"#### {ck} {cv['name']}\n\n")
            cc = cv.get('content')
            if cc:
                if isinstance(cc, str):
                    out.append(f"{cc}\n\n")
                elif isinstance(cc, dict):
                    for dk, dv in cc.items():
                        out.append(f"- **{dk}**：{dv}\n")
                    out.append("\n")
            else:
                out.append("（暂无内容）\n\n")
            for dk, dv in cv.get('children', {}).items():
                out.append(f"##### {dk} {dv['name']}\n\n")
                dc = dv.get('content')
                status = dv.get('status','')
                if status:
                    out.append(f"*状态：{status}*\n\n")
                if dc:
                    if isinstance(dc, str):
                        out.append(f"{dc}\n\n")
                    elif isinstance(dc, dict):
                        for ek, ev in dc.items():
                            out.append(f"- **{ek}**：{ev}\n")
                        out.append("\n")
                else:
                    out.append("（暂无内容）\n\n")
    DOWNLOAD = "/sdcard/Download"
    if not os.path.isdir(DOWNLOAD):
        DOWNLOAD = os.path.expanduser("~/Downloads")
    os.makedirs(DOWNLOAD, exist_ok=True)
    md_path = os.path.join(DOWNLOAD, "zhongqu_protocol.md")
    with open(md_path, "w", encoding="utf-8") as f:
        f.writelines(out)
    print(f"✅ 已导出：{md_path}")

def _proto_meta(d):
    meta = d['meta']
    print(f"\n当前版本：{meta['version']}")
    v = input("新版本号（留空不改）：").strip()
    print(f"当前状态：{meta['status']}")
    s = input("新状态描述（留空不改）：").strip()
    if v: meta['version'] = v
    if s: meta['status'] = s
    _proto_save(d)
    print("✅ 已更新")

while True:
    print("\n" + "="*35)
    print("  协议管理")
    print("="*35)
    print("  1. 查看协议树")
    print("  2. 查看节点详情")
    print("  3. 添加节点")
    print("  4. 编辑节点")
    print("  5. 删除节点")
    print("  6. 导出MD")
    print("  7. 修改版本/状态")
    print("  0. 返回")
    print("-"*35)
    c = input("选择：").strip()
    if c == "0":
        break
    pd = _proto_load()
    if c == "1":
        _proto_show(pd)
    elif c == "2":
        _proto_view(pd)
    elif c == "3":
        _proto_add(pd)
    elif c == "4":
        _proto_edit(pd)
    elif c == "5":
        _proto_delete(pd)
    elif c == "6":
        _proto_export_md(pd)
    elif c == "7":
        _proto_meta(pd)
    else:
        print("无效选择")
    input("\n回车继续...")

