# @记
# 需求：类脑模块注册中心，解决模块间依赖问题
# 设计：
#   1. 所有模块通过 register() 注册自己的类
#   2. 其他模块通过 get() 获取，不直接 import
#   3. 运行时动态组装
# 注意：这是所有脑模块的基础，必须第一个创建
# @毕

import sys

class BrainRegistry:
    """脑模块注册中心"""

    _classes = {}
    _instances = {}

    @classmethod
    def register(cls, name, obj):
        """注册一个类或实例"""
        cls._classes[name] = obj
        return obj

    @classmethod
    def get(cls, name, default=None):
        """获取已注册的类"""
        return cls._classes.get(name, default)

    @classmethod
    def get_instance(cls, name, *args, **kwargs):
        """获取一个实例（自动创建）"""
        if name not in cls._instances:
            cls_class = cls.get(name)
            if cls_class:
                cls._instances[name] = cls_class(*args, **kwargs)
        return cls._instances.get(name)

    @classmethod
    def create(cls, name, *args, **kwargs):
        """创建一个新实例"""
        cls_class = cls.get(name)
        if cls_class:
            return cls_class(*args, **kwargs)
        return None

    @classmethod
    def list(cls):
        """列出所有已注册模块"""
        return list(cls._classes.keys())

    @classmethod
    def clear(cls):
        """清空注册"""
        cls._classes.clear()
        cls._instances.clear()


# 装饰器：自动注册
def register(name=None):
    """装饰器，自动将类注册到中心"""
    def decorator(cls):
        reg_name = name or cls.__name__
        BrainRegistry.register(reg_name, cls)
        return cls
    return decorator


# 便捷函数
def get_module(name):
    return BrainRegistry.get(name)

def create_module(name, *args, **kwargs):
    return BrainRegistry.create(name, *args, **kwargs)


# 自动注册自身（供其他模块使用）
BrainRegistry.register('BrainRegistry', BrainRegistry)

print("✅ 脑_注册中心 已加载")

