# @记
# 需求：类脑神经网络辅助函数
# 设计：
#   1. 脉冲记录器
#   2. 权重分析器
#   3. 配置管理器
#   4. 文本可视化工具
# 注意：独立模块，无外部依赖
# @毕

import numpy as np
import json
import os
from collections import deque
from datetime import datetime


class SpikeRecorder:
    """脉冲记录器"""

    def __init__(self, max_length=10000):
        self.spikes = deque(maxlen=max_length)
        self.times = deque(maxlen=max_length)
        self.neuron_count = 0

    def record(self, time, spikes):
        """记录脉冲"""
        self.spikes.append(spikes)
        self.times.append(time)
        if spikes:
            self.neuron_count = max(self.neuron_count, max(spikes) + 1)

    def get_raster_data(self):
        """获取光栅图数据 [(time, neuron_idx), ...]"""
        data = []
        for t, sp_list in zip(self.times, self.spikes):
            for idx in sp_list:
                data.append((t, idx))
        return data

    def get_firing_rate(self, neuron_idx, time_window=None):
        """计算神经元发放率 (Hz)"""
        if time_window is None and self.times:
            time_window = max(self.times) - min(self.times) if len(self.times) > 1 else 1

        count = 0
        for t, sp_list in zip(self.times, self.spikes):
            if neuron_idx in sp_list:
                count += 1

        if time_window and time_window > 0:
            return count / (time_window / 1000.0)
        return 0

    def get_population_rate(self, time_window=None):
        """计算群体平均发放率"""
        if not self.neuron_count:
            return 0

        total_rate = 0
        for i in range(self.neuron_count):
            total_rate += self.get_firing_rate(i, time_window)
        return total_rate / self.neuron_count

    def get_isi(self, neuron_idx):
        """计算峰峰间隔 (ms)"""
        spike_times = []
        for t, sp_list in zip(self.times, self.spikes):
            if neuron_idx in sp_list:
                spike_times.append(t)

        if len(spike_times) < 2:
            return []

        return [spike_times[i+1] - spike_times[i] for i in range(len(spike_times)-1)]

    def clear(self):
        """清空记录"""
        self.spikes.clear()
        self.times.clear()
        self.neuron_count = 0


class WeightAnalyzer:
    """突触权重分析器"""

    def __init__(self, max_history=100):
        self.history = []  # [(time, stats)]
        self.max_history = max_history

    def snapshot(self, time, weights):
        """记录权重快照"""
        if not weights:
            return

        stats = {
            'time': time,
            'mean': float(np.mean(weights)),
            'std': float(np.std(weights)),
            'min': float(np.min(weights)),
            'max': float(np.max(weights)),
            'median': float(np.median(weights)),
            'count': len(weights)
        }

        # 直方图 (10 bins)
        hist, edges = np.histogram(weights, bins=10)
        stats['histogram'] = hist.tolist()
        stats['hist_edges'] = edges.tolist()

        self.history.append(stats)

        # 限制历史长度
        if len(self.history) > self.max_history:
            self.history.pop(0)

    def get_trend(self):
        """获取权重趋势"""
        return [(h['time'], h['mean']) for h in self.history]

    def get_latest(self):
        """获取最新统计"""
        return self.history[-1] if self.history else None

    def get_weight_change(self):
        """获取总变化量"""
        if len(self.history) < 2:
            return 0
        return self.history[-1]['mean'] - self.history[0]['mean']


class ConfigManager:
    """配置管理器"""

    DEFAULT_CONFIG = {
        'dt': 0.5,
        'neuron_type': 'lif',
        'learning_rate': 0.1,
        'dopamine_tau': 100,
        'wm_capacity': 30,
        'wm_duration': 1000,
        'connection_density': {
            'sensory_feature': 0.2,
            'feature_cognitive': 0.15,
            'cognitive_motor': 0.2,
            'motor_cognitive': 0.1
        },
        'stimulus': {
            'default_current': 1.5,
            'default_duration': 200
        }
    }

    def __init__(self, config_path=None):
        self.config = self.DEFAULT_CONFIG.copy()
        self.config_path = config_path
        if config_path and os.path.exists(config_path):
            self.load()

    def get(self, key, default=None):
        """获取配置"""
        keys = key.split('.')
        value = self.config
        for k in keys:
            if isinstance(value, dict):
                value = value.get(k)
            else:
                return default
            if value is None:
                return default
        return value

    def set(self, key, value):
        """设置配置"""
        keys = key.split('.')
        target = self.config
        for k in keys[:-1]:
            if k not in target:
                target[k] = {}
            target = target[k]
        target[keys[-1]] = value

    def load(self):
        """加载配置文件"""
        try:
            with open(self.config_path, 'r', encoding='utf-8') as f:
                loaded = json.load(f)
                self._deep_update(self.config, loaded)
        except Exception as e:
            print(f"加载配置失败: {e}")

    def save(self):
        """保存配置文件"""
        if not self.config_path:
            return
        try:
            with open(self.config_path, 'w', encoding='utf-8') as f:
                json.dump(self.config, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"保存配置失败: {e}")

    def reset(self):
        """重置为默认配置"""
        self.config = self.DEFAULT_CONFIG.copy()

    def _deep_update(self, base, update):
        """深度更新字典"""
        for key, value in update.items():
            if isinstance(value, dict) and key in base and isinstance(base[key], dict):
                self._deep_update(base[key], value)
            else:
                base[key] = value


class TextVisualizer:
    """文本可视化工具"""

    @staticmethod
    def weight_histogram(weights, bins=10, width=40):
        """打印权重直方图"""
        if not weights:
            return "  (无权重数据)"

        hist, edges = np.histogram(weights, bins=bins)
        max_count = max(hist) if hist.max() > 0 else 1

        lines = ["\n权重分布:"]
        for i in range(bins):
            bar_len = int(hist[i] / max_count * width)
            bar = "█" * bar_len if bar_len > 0 else "·"
            lines.append(f"  {edges[i]:.2f}-{edges[i+1]:.2f}: {bar} ({hist[i]})")

        return "\n".join(lines)

    @staticmethod
    def activity_heatmap(activity, width=20, height=10):
        """打印活动热力图"""
        if not activity:
            return "  (无活动数据)"

        max_act = max(activity) if activity else 1
        if max_act == 0:
            max_act = 1

        chars = " ▁▂▃▄▅▆▇█"
        lines = ["\n神经元活动热力图:"]

        n_neurons = len(activity)
        cell_width = max(1, width // height) if height > 0 else 1
        rows = min(height, (n_neurons + cell_width - 1) // cell_width)

        for r in range(rows):
            start = r * cell_width
            end = min(start + cell_width, n_neurons)
            line = ""
            for i in range(start, end):
                intensity = int(activity[i] / max_act * (len(chars) - 1))
                line += chars[intensity]
            lines.append(f"  {line}")

        return "\n".join(lines)

    @staticmethod
    def raster_plot(raster_data, max_neurons=30, width=60):
        """打印脉冲光栅图"""
        if not raster_data:
            return "  (无脉冲数据)"

        # 分组
        neuron_spikes = {}
        max_time = 0
        for t, idx in raster_data:
            if idx < max_neurons:
                if idx not in neuron_spikes:
                    neuron_spikes[idx] = []
                neuron_spikes[idx].append(t)
                max_time = max(max_time, t)

        if max_time == 0:
            max_time = 1

        lines = [f"\n脉冲光栅图 (前{max_neurons}神经元):", "  时间 →"]

        for idx in sorted(neuron_spikes.keys())[:max_neurons]:
            line = [" " for _ in range(width)]
            for t in neuron_spikes[idx]:
                pos = int(t / max_time * (width - 1))
                if pos < width:
                    line[pos] = "█"
            lines.append(f"  N{idx:3d}: " + "".join(line))

        return "\n".join(lines)

    @staticmethod
    def network_summary(network):
        """打印网络摘要"""
        if not network:
            return "网络未初始化"

        stats = network.get_stats()
        lines = [
            "\n" + "="*40,
            "  网络摘要",
            "="*40,
            f"  时间: {stats['time']:.0f}ms",
            f"  神经元: {stats['active_neurons']}/{stats['total_neurons']} 活跃",
            f"  突触数: {stats['connections']}",
            f"  总脉冲: {stats['total_spikes']}",
            f"  平均权重: {stats['avg_weight']:.4f}",
            f"  多巴胺: {stats['dopamine']:.3f}",
            "="*40
        ]
        return "\n".join(lines)


# 便捷创建函数
def create_recorder(max_length=10000):
    return SpikeRecorder(max_length)

def create_analyzer(max_history=100):
    return WeightAnalyzer(max_history)

def create_config(path=None):
    return ConfigManager(path)

